import { Button, Card, CardContent, CardHeader, Container, Dialog, DialogContent, DialogTitle, Grid, List, ListItem, makeStyles, Paper, Typography } from '@material-ui/core'
import React from 'react'
import { useState } from 'react'

const useStyle = makeStyles(theme => {
    return {
        title: {
            textAlign: 'center'
        },
        answers: {
            border: '1px solid #777'
        }
    }
})


export default function Quiz() {
    const classes = useStyle()
    const [quiz, setQuiz] = useState(false);

    const openQuiz = () => {
        setQuiz(true)
    };
    const closeQuiz = () => {
        setQuiz(false)
    };

    return (
        <>
            <Button variant='contained' color='secondary' onClick={openQuiz}>
                Open Dialog
            </Button>
            <Dialog open={quiz} onClose={closeQuiz} fullScreen>
                <DialogTitle>Web Application Development</DialogTitle>
                <DialogContent>
                    <Card elevation={10} >
                        <Container>
                            <CardHeader title='Quiz 1' />
                            <CardContent>
                                <Grid container spacing={1}>

                                    <Grid item xs={12}>
                                        <Typography>
                                            Questions will be here.
                                        </Typography>
                                    </Grid>

                                    <Grid item xs={12}>
                                        <List>
                                            <ListItem className={classes.answers} button >Answers are here</ListItem>
                                            <ListItem button >Answers are here</ListItem>
                                            <ListItem button >Answers are here</ListItem>
                                            <ListItem button >Answers are here</ListItem>
                                        </List>
                                    </Grid>

                                </Grid>
                            </CardContent>
                        </Container>
                    </Card>
                </DialogContent>
            </Dialog>
        </>
    )
}
